import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Paths;

public class SecurePathTraversal {

    public static void main(String[] args) {
        String userInput = "../../../../../etc/passwd"; // User input containing path traversal

        String directory = "/var/www/public/"; // Base directory where files are supposed to be located

        String normalizedPath = new File(directory, userInput).getCanonicalPath(); // Normalize the path

        if (!normalizedPath.startsWith(directory)) {
            System.out.println("Invalid path provided");
            return;
        }

        File file = new File(normalizedPath);

        try {
            if (file.exists()) {
                byte[] fileBytes = Files.readAllBytes(file.toPath());
                System.out.println(new String(fileBytes));
            } else {
                System.out.println("File not found");
            }
        } catch (IOException e) {
            System.err.println("Error reading file: " + e.getMessage());
        }
    }
}

